def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity == 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 2:
            priorities[i] = ratio ** 4 + np.sqrt(ratio)
        elif 1 < ratio <= 2:
            priorities[i] = (ratio ** 3) * 1.2
        elif ratio == 1:
            priorities[i] = 0
        else:
            log_ratio = np.log(ratio)
            if log_ratio < -2:
                priorities[i] = (-log_ratio) ** 2 * 2
            elif -2 <= log_ratio < -0.5:
                priorities[i] = (-log_ratio) * 1.8
            else:
                priorities[i] = (-log_ratio) * 1.2
        if capacity < item * 1.2:
            priorities[i] *= 2
        elif capacity < item * 1.5:
            priorities[i] *= 1.5
        else:
            priorities[i] *= 0.5
        if priorities[i] > 10:
            priorities[i] = np.log(priorities[i]) * 5
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        min_priority = np.min(finite_priorities)
        max_priority = np.max(finite_priorities)
        for i in range(len(priorities)):
            if not np.isfinite(priorities[i]):
                priorities[i] = max_priority * 10
            elif priorities[i] < min_priority * 0.1:
                priorities[i] = min_priority * 0.1
            elif priorities[i] > max_priority * 0.9:
                priorities[i] = max_priority * 0.9
    else:
        priorities.fill(np.inf)
    for i in range(len(priorities)):
        if priorities[i] < 0:
            priorities[i] = 0
    return priorities
